@app.route("/reset-mfa/confirm", methods=["GET", "POST"])
def reset_mfa_confirm():
    token = request.args.get("token", "").strip()
    if request.method == "POST":
        data = request.get_json(silent=True) or {}
        token = (data.get("token") or token or "").strip()

    if not token:
        return json_error("Missing token.", 400, code="missing_token")

    row, err = consume_reset_token(token)
    if err:
        if err == "expired":
            return json_error("Reset link expired.", 400, code="token_expired")
        if err == "used":
            return json_error("Reset link already used.", 400, code="token_used")
        return json_error("Invalid reset link.", 400, code="token_invalid")

    user = get_user_by_id(int(row["user_id"]))
    if not user:
        return json_error("Invalid reset link.", 400, code="token_invalid")

    disable_mfa_for_user(user["id"])
    return json_ok(
        {
            "message": "MFA has been reset and disabled. You can now log in with just your password.",
            "user_id": user["id"],
            "email": user["email"],
            "mfa_enabled": False,
        }
    )


@app.route("/admin/debug/users", methods=["GET"])
def debug_users():
    if os.environ.get("ENABLE_DEBUG_ADMIN", "0") != "1":
        return json_error("Not found.", 404, code="not_found")
    db = get_db()
    rows = db.execute("SELECT id, email, mfa_enabled, created_at, updated_at FROM users ORDER BY id").fetchall()
    return json_ok({"users": [dict(r) for r in rows]})


